import base64

# A minimal valid docx base64 string
valid_docx_b64 = ""

with open('backend/app/services/onlyoffice_drafts.py', 'r') as f:
    content = f.read()

import re
replacement = """def build_blank_docx_bytes(title: str) -> bytes:
    import base64
    valid_docx_b64 = ""
    return base64.b64decode(valid_docx_b64)
"""
new_content = re.sub(r'def build_blank_docx_bytes\(title: str\) -> bytes:.*?(?=\n\n\n|\Z)', replacement, content, flags=re.DOTALL)
with open('backend/app/services/onlyoffice_drafts.py', 'w') as f:
    f.write(new_content)
print("Updated successfully")
